#!/usr/bin/env bash
# hypothesis-driven-problem-solvin.sh — 假设驱动问题解决（hypothesis-driven problem solving） SOP walkthrough for 管理咨询.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="管理咨询"
WORKFLOW="假设驱动问题解决（hypothesis-driven problem solving）"

usage() {
  cat <<EOF
hypothesis-driven-problem-solvin.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./hypothesis-driven-problem-solvin.sh             # interactive
  ./hypothesis-driven-problem-solvin.sh --dry-run
  ./hypothesis-driven-problem-solvin.sh --json
  ./hypothesis-driven-problem-solvin.sh --explain
  ./hypothesis-driven-problem-solvin.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "假设驱动问题解决（hypothesis-driven problem solving）" 工作流。

一句话: 咨询的「思考引擎」—— 把一个模糊大问题，经「定义 → MECE 拆 issue tree → 立可证伪假设 → 设计分析验证/证伪 → 迭代」收敛成有事实支撑的答案。这是 workflow 1 的核心子流程，也是案例面试（workflow 4）考的东西，是这一行最可标准化、最易蒸出高质量的方法论。

入门 SOP 共 5 步, 失败模式自检 5 项。

相关心智模型:
  • 假设驱动是地图不是答案：先射箭再画靶 ⇄ 随时 kill 假设（第一性张力）: 面对模糊大问题，资深咨询人不从穷举数据出发，而是 Day-1 就基于经验立一个**可证伪**的初步答案（hypothesis / initial hypothesis）当地图，再只做能 kill 或 
  • 战略 = 做选择 / 做不同，不是运营效率、不是愿望清单: 这行顶级战略 figure 跨流派一致——战略的本质是**逼自己做取舍**（Martin：where-to-play × how-to-win 两个不可分割的选择；Rumelt：kernel = 诊断

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**定义问题**：写出具体、有边界、可验证的问题陈述（同 workflow 1 step 3）。(evidence: [T04-S035, T03-S014])"
  "**MECE 拆 issue tree（结构化）**：把核心问题逐层向右拆成**相互独立、完全穷尽**的子问题，每个叶子能 yes/no 或量化验证。常用 driver tree（利润 = 量 × 价 − 成本…）做定量骨架。(evidence: [T03-S002, T06-S004, T06-S007])"
  "**提假设（hypothesis）**：对每个关键分支立一个**可证伪**的假设（「我猜利润下滑主因是低端机型萎缩」）；项目级别立 Day-1 答案假设。(evidence: [T04-S037, T03-S002])"
  "**设计分析去验证/证伪**：为每个假设设计**最小必要分析**（哪个数据/模型/专家访谈能 kill 或 confirm 它），而非穷举。(evidence: [T03-S002, T06-S009])"
  "**跑分析 + 迭代**：执行分析，看证据。假设被证伪 → 回到 tree 换一个分支/假设重来；被支持 → 深挖并锁定。循环到收敛。(evidence: [T04-S037, T04-S035])"
)
declare -a FAILURE_MODES=(
  "**拆桶重叠又漏项（MECE 失败）**：issue tree 的子项互相打架或漏掉关键分支。避免：每层拆完检查「这些桶有重叠吗？合起来穷尽吗？」**自检**：「把这层所有桶加起来，等于上一层吗？有没有哪个东西能同时归两个桶？」"
  "**把 issue tree 做成发散 mind map**：每支不指向可验证假设，沦为头脑风暴图。避免：强制每个叶子写一个能 yes/no 或量化检验的假设。**自检**：「这个叶子节点，我能设计一个分析去证伪它吗？不能就不是 issue tree。」"
  "**Confirmation bias（先有结论硬凑证据）**：把假设当既定结论，只找支持证据。避免：每个假设都主动设计一个能证伪它的分析。**自检**：「如果我的假设是错的，会是什么数据告诉我？我去找那个数据了吗？」"
  "**Boil the ocean（不会 80/20）**：不剪枝、每个分支都查到底。避免：拆完树立刻 prune，只攻 2-3 个高杠杆分支。**自检**：「这个分支就算分析出来，会改变最终建议吗？不会就剪掉。」"
  "**GenAI 跑出的分析不核验就用**：AI 幻觉的数字/引用直接进结论。避免：AI 输出的每个 claim 落到可追溯原始来源才采信。**自检**：「这个数字/引用，我能点到原始来源吗？还是只是 AI 说的？」(evidence: [T03-S009])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "hypothesis-driven-problem-solvin-walkthrough"
fi
